  var debugTransitionsInput = byId("debug-transitions");
  var pager = byId("pager");
  var pageSize = byId("page-size");
  var playbackStatus = byId("playback-status");
  var modeReadout = byId("mode-readout");
  var speedReadout = byId("speed-readout");
  var fpsReadout = byId("fps-readout");
  var holdReadout = byId("hold-readout");
